const accounts = $json.accounts;
const count = accounts.length;
const date = new Date().toISOString().slice(0, 10);

const sentimentEmoji = (s) => {
  if (!s) return '-';
  const val = s.toLowerCase();
  if (val === 'positive') return ':large_green_circle: Positive';
  if (val === 'negative') return ':red_circle: Negative';
  if (val === 'neutral') return ':large_yellow_circle: Neutral';
  return s;
};

const formatMRR = (mrr) => {
  if (mrr == null) return 'N/A';
  return '$' + Number(mrr).toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 });
};

let rows = accounts.map((a, i) => {
  const rank = i + 1;
  const name = a.Name || 'Unknown';
  const score = a.Recent_Health_Score__c != null ? a.Recent_Health_Score__c : 'N/A';
  const mrr = formatMRR(a.Average_MRR__c);
  const sentiment = sentimentEmoji(a.Account_Owner_Sentiment__c);
  return rank + '. *' + name + '* -- Score: ' + score + ' | MRR: ' + mrr + ' | Sentiment: ' + sentiment;
}).join('\n');

const message = ':warning: *Daily At-Risk Account Summary -- ' + date + '*\n' +
  count + ' account(s) with Health Score below 50 (worst first):\n\n' +
  rows;

return [{ json: { message } }];
